import numpy as np
from typing import List, Dict
from dataclasses import dataclass
import json

# Simulated embedding model (in production, use Sentence-Transformers, OpenAI, etc.)
def get_embedding(text: str) -> np.ndarray:
    """Mock embedding function. Returns 8-dimensional vector for demo."""
    np.random.seed(hash(text) % 2**32)  # Deterministic for same text
    return np.random.randn(8)

@dataclass
class CricketChunk:
    """Represents a chunk from cricket knowledge base."""
    chunk_id: str
    content: str
    metadata: Dict[str, str]  # e.g., {'player': 'Rohit Sharma', 'match': 'Australia_Test_2023'}
    vector: np.ndarray = None

    def vectorize(self):
        """Convert chunk content to embedding vector."""
        self.vector = get_embedding(self.content)

